updateVisibility() {
    const playerX = player.mesh.position.x;
    const playerZ = player.mesh.position.z;
    const enemyX = this.mesh.position.x;
    const enemyZ = this.mesh.position.z;
    const dist = distance(playerX, 0, playerZ, enemyX, 0, enemyZ);

    this.isFar = dist > 100;
    this.isVeryFar = dist > 300;

    // Visibility conditions, adjusted based on distance
