  if (angleDiff < -Math.PI) rotDiff += 2 * Math.PI;

  const maxRotationSpeed = this.isFar ? 0.05 : 0.2;
  rotDiff = Math.max(-maxRotationSpeed, Math.min(maxRotationSpeed, rotDiff));

